import React from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';

const Navbar: React.FC = () => {
    const [isScrolled, setIsScrolled] = React.useState(false);
    const [plannerActive, setPlannerActive] = React.useState(false);
    const location = useLocation();

    React.useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 24);
        };

        handleScroll();
        window.addEventListener('scroll', handleScroll, { passive: true });

        return () => {
            window.removeEventListener('scroll', handleScroll);
        };
    }, []);

    React.useEffect(() => {
        const syncPlannerState = () => {
            const activeOnHome = location.pathname === '/' && document.body.dataset.plannerActive === 'true';
            setPlannerActive(activeOnHome);
        };

        syncPlannerState();
        window.addEventListener('planner-active-change', syncPlannerState as EventListener);

        return () => {
            window.removeEventListener('planner-active-change', syncPlannerState as EventListener);
        };
    }, [location.pathname]);

    const navItems = [
        { name: 'Home', path: '/' },
        { name: 'Map', path: '/map' },
        { name: 'Itinerary', path: '/itinerary' },
        { name: 'Login', path: '/login' },
        { name: 'Profile', path: '/profile' },
    ];

    return (
        <div className={`sticky top-3 z-50 px-3 md:px-4 ${plannerActive ? 'hidden' : ''}`}>
            <motion.nav
                initial={{ y: -20, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ duration: 0.45, ease: 'easeOut' }}
                className={`glass-nav mx-auto max-w-7xl border-white/10 transition-all duration-300 ${
                    isScrolled ? 'bg-bg1/72 backdrop-blur-xl' : 'bg-bg1/58 backdrop-blur-lg'
                }`}
                aria-label="Primary"
            >
                <div className={`flex items-center justify-between px-4 md:px-6 transition-all duration-300 ${isScrolled ? 'h-[4.1rem]' : 'h-[4.6rem]'}`}>
                    <Link
                        to="/"
                        className="group relative flex items-center gap-3 rounded-xl px-2 py-1 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/70"
                    >
                        <div className="absolute -inset-2 rounded-full bg-emerald/12 blur-xl opacity-0 transition-opacity duration-500 group-hover:opacity-100" />
                        <span className="relative text-3xl">🏙️</span>
                        <div className="relative flex flex-col tracking-tighter">
                            <span className="text-2xl font-black leading-none font-inter">
                                <span className="text-uncc-green">CLT</span>
                                <span className="text-uncc-gold">ourism</span>
                            </span>
                            <span className="mt-1 font-inter text-[10px] font-bold uppercase tracking-[0.3em] text-muted">Queen City</span>
                        </div>
                    </Link>

                    <div className="hidden items-center gap-1.5 md:flex" role="list" aria-label="Main navigation links">
                        {navItems.map((item) => {
                            const isActive = item.path === '/'
                                ? location.pathname === '/'
                                : location.pathname.startsWith(item.path);

                            return (
                                <NavLink
                                    key={item.name}
                                    to={item.path}
                                    className={({ isActive: navIsActive }) => {
                                        const activeState = item.path === '/'
                                            ? location.pathname === '/'
                                            : navIsActive || location.pathname.startsWith(item.path);

                                        return `relative rounded-xl px-4 py-2 text-[11px] font-bold uppercase tracking-[0.16em] font-inter transition-colors duration-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-emerald/70 ${
                                            activeState ? 'text-white' : 'text-muted hover:text-white'
                                        }`;
                                    }}
                                >
                                    {isActive && (
                                        <motion.span
                                            layoutId="navbar-active-pill"
                                            className="absolute inset-0 -z-10 rounded-xl border border-stroke bg-white/[0.06]"
                                            transition={{ type: 'spring', bounce: 0.25, duration: 0.45 }}
                                        />
                                    )}
                                    <span>{item.name}</span>
                                    {isActive && (
                                        <motion.span
                                            layoutId="navbar-active-underline"
                                            className="absolute -bottom-0.5 left-3 right-3 h-[2px] rounded-full bg-gradient-to-r from-emerald to-gold"
                                            transition={{ type: 'spring', stiffness: 380, damping: 32 }}
                                        />
                                    )}
                                </NavLink>
                            );
                        })}
                    </div>
                </div>
            </motion.nav>
        </div>
    );
};

export default Navbar;
